-- ════════════════════════════════════════════════════════════
-- Обновление карточек «Инструменты продаж» — реальные комбинации
-- из позиций YAHYA: 3 апсейл + 5 кросс-селл + 4 бандл = 12 шт.
-- ════════════════════════════════════════════════════════════
-- Запуск: Supabase Dashboard → SQL Editor → New query → вставить → Run
-- Безопасно повторно: UPSERT, существующие IDs (up-1..3, cs-1..3, bn-1..3)
-- перезапишутся, новые (cs-4, cs-5, bn-4) — добавятся.
-- ════════════════════════════════════════════════════════════

INSERT INTO tools (id, data) VALUES
  ('up-1', $${"id":"up-1","tool_type":"upsell","title":"Больше вкусов / больше дней","when_to_use":"Клиент колеблется размером набора конфет","script_line":"«Если на 4 — берите на 9: попробуете все вкусы сразу. Если на 9 — берите на 15: 9 быстро съедятся, а 15 хватит на пару вечеров с чаем.»","example":"4 конф 680 → 9 конф 1390 (попробовать весь ассортимент) · 9 конф 1390 → 15 конф 2210 (хватит надолго)"}$$::jsonb),

  ('up-2', $${"id":"up-2","tool_type":"upsell","title":"Сироп или авторский кофе","when_to_use":"Клиент заказывает обычный латте или капучино","script_line":"«Добавьте сироп — имбирный пряник, лаванда, малина — обычный латте сразу становится авторским. Или возьмите Раф Лаванда / Раф Малина — наш фирменный.»","example":"Латте 320 → Латте имбирный пряник 330 · Капучино 250 → Раф Лаванда 390 · Латте 320 → Раф Малина 390"}$$::jsonb),

  ('up-3', $${"id":"up-3","tool_type":"upsell","title":"Премиум-плитка (не масс-маркет)","when_to_use":"Клиент берёт обычную плитку 450–540 сом","script_line":"«Попробуйте Origine Papouasie 35% или дубайский с фисташкой. У нас не масс-маркет — таких плиток в супермаркете не найдёте. Дубайский вообще авторский, делаем сами.»","example":"Молочный с пралине 450 → Origine 650 · → Дубайский батончик 380/50г · → Дубайский плитка 750/100г"}$$::jsonb),

  ('cs-1', $${"id":"cs-1","tool_type":"crosssell","title":"В зале: конфета или нуга к напитку","when_to_use":"Гость заказал кофе или чай и остался в зале","script_line":"«К напитку одну конфету или кусочек нуги — у нас подобраны пары. Эспрессо + трюфель апельсин, латте + чай с печеньем, чай + нуга абрикос-фисташка.»","example":"Эспрессо 180 + Трюфель апельсин 130 = 310 · Латте 320 + Чай с печеньем 130 = 450 · Эрл Грей 450 + Нуга 395"}$$::jsonb),

  ('cs-2', $${"id":"cs-2","tool_type":"crosssell","title":"С собой: круассан или сэндвич","when_to_use":"Клиент забирает напиток на вынос","script_line":"«Возьмите круассан или сэндвич — одного кофе до офиса не хватит, проголодаетесь. Свежее, с утра.»","example":"Капучино 250 + круассан · Латте 320 + сэндвич · Американо 220 + круассан шоколадный"}$$::jsonb),

  ('cs-3', $${"id":"cs-3","tool_type":"crosssell","title":"Крафтовый пакет — на чек от 1500","when_to_use":"Чек уже от 1500 сом, особенно когда покупка для подарка","script_line":"«Упакуем в наш фирменный крафт-пакет — выглядит как из бутика. Платный, но на такой подарок без него никак.»","example":"ВАЖНО: не предлагать на маленькие чеки. Срабатывает, когда сумма уже большая и упаковка подчёркивает ценность подарка."}$$::jsonb),

  ('cs-4', $${"id":"cs-4","tool_type":"crosssell","title":"К чаю: нуга, сабле или мёд","when_to_use":"Клиент заказал чайник или порцию чая в зале","script_line":"«К чаю нуга или сабле в шоколаде — кусочками на тарелочке. Или фруктовый мёд с апельсином — для тех, кто не любит сладкое.»","example":"Эрл Грей 450 + Нуга абрикос-фисташка 395 · Bold Fruit 450 + Сабле малина 750 · Облепиховый + Плитка облепиха-фисташка"}$$::jsonb),

  ('cs-5', $${"id":"cs-5","tool_type":"crosssell","title":"Вторая плитка — себе на потом","when_to_use":"Клиент берёт одну плитку в магазине","script_line":"«Возьмите вторую — одна на сейчас, другая на работу. Тёмный 64% и Молочный NO SUGAR — день и вечер, разные настроения.»","example":"Молочный с пралине 450 + Тёмный 64% 650 = 1100 · Origine 650 + NO SUGAR 850 = 1500"}$$::jsonb),

  ('bn-1', $${"id":"bn-1","tool_type":"bundle","title":"«Утро»: кофе + конфета","when_to_use":"Клиент утром берёт кофе с собой","script_line":"«Возьмите утреннее комбо — капучино и одну конфету. Кофе бодрит, конфета даёт настроение, всё в одной руке. От 380.»","example":"Капучино 250 + Чай с печеньем 130 = 380 · Латте 320 + Кокос-миндаль 130 = 450 · Эспрессо 180 + 2 трюфеля = 440"}$$::jsonb),

  ('bn-2', $${"id":"bn-2","tool_type":"bundle","title":"«Подарок мужчине»: коллекция + сигары","when_to_use":"Подарок мужчине — день рождения, 23 февраля, благодарность партнёру","script_line":"«Соберём мужской: коллекция «СИЛА» (1570, 9 конфет) и сигары из тёмного шоколада (1500). Эффектно, никто такого не дарит. Всего 3070.»","example":"«СИЛА» 9 1570 + Сигары 1500 = 3070 · «ЧЕСТЬ» 16 2530 + Сигары 1500 = 4030"}$$::jsonb),

  ('bn-3', $${"id":"bn-3","tool_type":"bundle","title":"«Подарок женщине»: набор + шоко-фигура","when_to_use":"Подарок женщине — 8 марта, день рождения, свидание","script_line":"«Возьмите набор на 9 корпусных конфет (1390) и шоколадную бутылку шампанского (1800) — подарок выглядит на 5000, а заплатите 3190. Если шампанского нет — возьмите сигары или пасхальное яйцо, тоже эффектно.»","example":"9 корп 1390 + Шампанское 1800 = 3190 · 9 корп 1390 + Сигары 1500 = 2890 · 9 корп 1390 + Пасхальное яйцо 3300 = 4690 (премиум)"}$$::jsonb),

  ('bn-4', $${"id":"bn-4","tool_type":"bundle","title":"«Без сахара» — для тех, кто следит за фигурой","when_to_use":"Клиент спрашивает «есть без сахара?», говорит про диету или здоровье","script_line":"«Соберём всё без сахара: плитка молочный 33,9% NO SUGAR (850) и драже миндаль без сахара (990). 1840 — на неделю спокойно. На мальтите, без потери вкуса.»","example":"NO SUGAR молочный 850 + Драже без сахара 990 = 1840 · + Драже фундук без сахара 1190"}$$::jsonb)

ON CONFLICT (id) DO UPDATE SET
  data = EXCLUDED.data,
  updated_at = now();

